def check_ca_fop_symbol_present_on_exempt_product(product: dict) -> str | None:
    """
    Returns the rule tag if the compound condition is violated (i.e., all three
    numeric fields are present and greater than 0.0). Otherwise returns None.
    """
    tag = "ca-fop-symbol-present-on-exempt-product"
    # Required fields
    required_fields = ["fop_symbol_present", "fop_exempt_proxy", "product_is_prepackaged_proxy"]
    values = {}
    for field in required_fields:
        if field not in product:
            return None
        val = product[field]
        # Missing or non‑numeric values cause the rule to be ignored
        if val is None:
            return None
        if not isinstance(val, (int, float)):
            return None
        values[field] = float(val)

    if (
        values["fop_symbol_present"] > 0.0
        and values["fop_exempt_proxy"] > 0.0
        and values["product_is_prepackaged_proxy"] > 0.0
    ):
        return tag
    return None

